import {
	Scene,
	PerspectiveCamera,
	WebGLRenderer,
	AmbientLight,
	SpotLight,
	Color,
	Clock,
	SRGBColorSpace,
} from 'three'
import { CAMERA_3D, LIGHTING_3D } from '../constants'

export class SceneManager {
	public scene: Scene
	public camera: PerspectiveCamera
	public renderer: WebGLRenderer
	public clock: Clock

	private animationFrameId: number | null = null
	private updateCallbacks: ((delta: number) => void)[] = []
	private resizeCallbacks: ((width: number, height: number) => void)[] = []

	constructor(container: HTMLElement, clearColor: string = '#0a0a1a') {
		this.scene = new Scene()
		this.clock = new Clock()

		// Camera
		this.camera = new PerspectiveCamera(
			CAMERA_3D.fov,
			container.clientWidth / container.clientHeight,
			CAMERA_3D.near,
			CAMERA_3D.far
		)
		this.camera.position.set(
			CAMERA_3D.position.x,
			CAMERA_3D.position.y,
			CAMERA_3D.position.z
		)
		this.camera.lookAt(
			CAMERA_3D.lookAt.x,
			CAMERA_3D.lookAt.y,
			CAMERA_3D.lookAt.z
		)

		// Renderer
		this.renderer = new WebGLRenderer({
			antialias: true,
			alpha: false,
		})
		this.renderer.setSize(container.clientWidth, container.clientHeight)
		this.renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2))
		this.renderer.outputColorSpace = SRGBColorSpace
		this.renderer.setClearColor(new Color(clearColor))
		container.appendChild(this.renderer.domElement)

		// Lighting
		const ambient = new AmbientLight(0xffffff, LIGHTING_3D.ambientIntensity)
		this.scene.add(ambient)

		const spot = new SpotLight(0xffffff, LIGHTING_3D.spotIntensity)
		spot.position.set(
			LIGHTING_3D.spotPosition.x,
			LIGHTING_3D.spotPosition.y,
			LIGHTING_3D.spotPosition.z
		)
		spot.angle = Math.PI / 4
		spot.penumbra = 0.5
		spot.decay = 1
		this.scene.add(spot)

		// Handle resize
		this.handleResize = this.handleResize.bind(this)
		window.addEventListener('resize', this.handleResize)
	}

	/** Register a per-frame update callback. */
	onUpdate(callback: (delta: number) => void) {
		this.updateCallbacks.push(callback)
	}

	/** Register a resize callback. */
	onResize(callback: (width: number, height: number) => void) {
		this.resizeCallbacks.push(callback)
	}

	/** Set the scene background clear color. */
	setClearColor(hex: string) {
		this.renderer.setClearColor(new Color(hex))
	}

	start() {
		const animate = () => {
			this.animationFrameId = requestAnimationFrame(animate)
			const delta = this.clock.getDelta()

			for (const cb of this.updateCallbacks) {
				cb(delta)
			}

			this.renderer.render(this.scene, this.camera)
		}
		animate()
	}

	stop() {
		if (this.animationFrameId !== null) {
			cancelAnimationFrame(this.animationFrameId)
			this.animationFrameId = null
		}
	}

	private handleResize() {
		const parent = this.renderer.domElement.parentElement
		if (!parent) return

		const width = parent.clientWidth
		const height = parent.clientHeight

		this.camera.aspect = width / height
		this.camera.updateProjectionMatrix()
		this.renderer.setSize(width, height)

		for (const cb of this.resizeCallbacks) {
			cb(width, height)
		}
	}

	dispose() {
		this.stop()
		window.removeEventListener('resize', this.handleResize)

		this.renderer.dispose()
		this.renderer.domElement.remove()

		this.scene.traverse(obj => {
			if ('geometry' in obj && obj.geometry) {
				;(obj as any).geometry.dispose()
			}
			if ('material' in obj && obj.material) {
				const material = obj.material as any
				if (Array.isArray(material)) {
					material.forEach((m: any) => m.dispose())
				} else {
					material.dispose()
				}
			}
		})

		this.updateCallbacks = []
		this.resizeCallbacks = []
	}
}
