import * as Tone from 'tone'
import { LANE_PITCHES } from '../constants'
import { transposeOctave } from './laneAssigner'
import {
	type InstrumentName,
	getInstrumentPreset,
} from './instrumentPresets'

class AudioManager {
	private synth: Tone.PolySynth | null = null
	private initialized = false
	private muted = false
	private currentInstrument: InstrumentName = 'piano'
	private sparkleOctaveOffset: number = 2

	// Background beat synths
	private drumSynth: Tone.MembraneSynth | null = null
	private hiHatSynth: Tone.MetalSynth | null = null
	private snareSynth: Tone.NoiseSynth | null = null
	private bassLoop: Tone.Loop | null = null
	private hiHatLoop: Tone.Loop | null = null
	private snareLoop: Tone.Loop | null = null
	private isPlaying = false

	// Sustained notes for hold notes
	private sustainedNotes: Map<string, boolean> = new Map()

	async init(): Promise<void> {
		if (this.initialized) return

		try {
			// Start Tone.js audio context
			await Tone.start()

			// Create a polyphonic synth and apply default instrument preset
			this.synth = new Tone.PolySynth(Tone.Synth).toDestination()
			this.setInstrument('piano')

			// Initialize drum synths for background beat
			this.initDrums()

			this.initialized = true
		} catch (error) {
			console.error('Failed to initialize audio:', error)
		}
	}

	private initDrums(): void {
		// Kick drum
		this.drumSynth = new Tone.MembraneSynth({
			pitchDecay: 0.05,
			octaves: 4,
			oscillator: { type: 'sine' },
			envelope: { attack: 0.001, decay: 0.4, sustain: 0.01, release: 1.4 },
		}).toDestination()
		this.drumSynth.volume.value = -8

		// Hi-hat
		this.hiHatSynth = new Tone.MetalSynth({
			envelope: { attack: 0.001, decay: 0.1, release: 0.01 },
			harmonicity: 5.1,
			modulationIndex: 32,
			resonance: 4000,
			octaves: 1.5,
		}).toDestination()
		this.hiHatSynth.volume.value = -20

		// Snare drum (noise-based)
		this.snareSynth = new Tone.NoiseSynth({
			noise: { type: 'white' },
			envelope: { attack: 0.001, decay: 0.2, sustain: 0, release: 0.1 },
		}).toDestination()
		this.snareSynth.volume.value = -12
	}

	startBackgroundBeat(
		bpm: number,
		track: 'chill' | 'default' | 'upbeat',
		cycle: number = 0,
		travelDelay: number = 0,
		beatsPerMeasure: number = 4
	): void {
		if (this.isPlaying) return

		Tone.Transport.bpm.value = bpm

		const beat = 60 / bpm // seconds per beat
		const measureDuration = beat * beatsPerMeasure
		const halfMeasure = measureDuration / 2
		const halfBeat = beat / 2

		if (track === 'chill') {
			if (cycle === 0) {
				// CYCLE 0: Kick on downbeat of each measure, hi-hat every beat
				this.bassLoop = new Tone.Loop(time => {
					if (!this.muted)
						this.drumSynth?.triggerAttackRelease('C1', '8n', time)
				}, measureDuration).start(travelDelay)

				this.hiHatLoop = new Tone.Loop(time => {
					if (!this.muted) this.hiHatSynth?.triggerAttackRelease('32n', time)
				}, beat).start(travelDelay)
			} else {
				// CYCLE 1+: Kick on 1, snare mid-measure, offbeat hi-hat
				this.bassLoop = new Tone.Loop(time => {
					if (!this.muted)
						this.drumSynth?.triggerAttackRelease('C1', '8n', time)
				}, measureDuration).start(travelDelay)

				this.snareLoop = new Tone.Loop(time => {
					if (!this.muted) this.snareSynth?.triggerAttackRelease('8n', time)
				}, measureDuration).start(travelDelay + halfMeasure)

				this.hiHatLoop = new Tone.Loop(time => {
					if (!this.muted) this.hiHatSynth?.triggerAttackRelease('32n', time)
				}, beat).start(travelDelay + halfBeat)
			}
		} else if (track === 'default') {
			if (cycle === 0) {
				// CYCLE 0: Standard rock beat - kick 1&3, snare 2&4, hi-hat quarter notes
				this.bassLoop = new Tone.Loop(time => {
					if (!this.muted)
						this.drumSynth?.triggerAttackRelease('C1', '8n', time)
				}, halfMeasure).start(travelDelay)

				this.snareLoop = new Tone.Loop(time => {
					if (!this.muted) this.snareSynth?.triggerAttackRelease('8n', time)
				}, halfMeasure).start(travelDelay + beat)

				this.hiHatLoop = new Tone.Loop(time => {
					if (!this.muted) this.hiHatSynth?.triggerAttackRelease('32n', time)
				}, beat).start(travelDelay)
			} else {
				// CYCLE 1+: Four-on-the-floor - kick every beat, snare 2&4, hi-hat 8n
				this.bassLoop = new Tone.Loop(time => {
					if (!this.muted)
						this.drumSynth?.triggerAttackRelease('C1', '8n', time)
				}, beat).start(travelDelay)

				this.snareLoop = new Tone.Loop(time => {
					if (!this.muted) this.snareSynth?.triggerAttackRelease('8n', time)
				}, halfMeasure).start(travelDelay + beat)

				this.hiHatLoop = new Tone.Loop(time => {
					if (!this.muted) this.hiHatSynth?.triggerAttackRelease('32n', time)
				}, halfBeat).start(travelDelay)
			}
		} else {
			// Upbeat
			if (cycle === 0) {
				// CYCLE 0: Driving rock - kick 1&3, snare 2&4, hi-hat 8n
				this.bassLoop = new Tone.Loop(time => {
					if (!this.muted)
						this.drumSynth?.triggerAttackRelease('C1', '8n', time)
				}, halfMeasure).start(travelDelay)

				this.snareLoop = new Tone.Loop(time => {
					if (!this.muted) this.snareSynth?.triggerAttackRelease('8n', time)
				}, halfMeasure).start(travelDelay + beat)

				this.hiHatLoop = new Tone.Loop(time => {
					if (!this.muted) this.hiHatSynth?.triggerAttackRelease('32n', time)
				}, halfBeat).start(travelDelay)
			} else {
				// CYCLE 1+: Double-time punk - kick every beat, snare every offbeat, hi-hat 8n
				this.bassLoop = new Tone.Loop(time => {
					if (!this.muted)
						this.drumSynth?.triggerAttackRelease('C1', '8n', time)
				}, beat).start(travelDelay)

				this.snareLoop = new Tone.Loop(time => {
					if (!this.muted) this.snareSynth?.triggerAttackRelease('8n', time)
				}, beat).start(travelDelay + halfBeat)

				this.hiHatLoop = new Tone.Loop(time => {
					if (!this.muted) this.hiHatSynth?.triggerAttackRelease('32n', time)
				}, halfBeat).start(travelDelay)
			}
		}

		Tone.Transport.start()
		this.isPlaying = true
	}

	startTransportOnly(bpm: number, travelDelay: number = 0): void {
		if (this.isPlaying) return
		Tone.Transport.bpm.value = bpm
		Tone.Transport.start(`+${travelDelay}`)
		this.isPlaying = true
	}

	stopBackgroundBeat(): void {
		Tone.Transport.stop()
		this.bassLoop?.stop()
		this.hiHatLoop?.stop()
		this.snareLoop?.stop()
		this.bassLoop?.dispose()
		this.hiHatLoop?.dispose()
		this.snareLoop?.dispose()
		this.bassLoop = null
		this.hiHatLoop = null
		this.snareLoop = null
		this.isPlaying = false
	}

	pauseBackgroundBeat(): void {
		if (this.isPlaying) {
			Tone.Transport.pause()
		}
	}

	resumeBackgroundBeat(): void {
		if (this.isPlaying) {
			Tone.Transport.start()
		}
	}

	/**
	 * Get the current Transport time in milliseconds.
	 * This is the single source of truth for all game timing.
	 */
	getTransportTime(): number {
		if (!this.isPlaying) return 0
		return Tone.Transport.seconds * 1000
	}

	/**
	 * Reset the Transport position to the beginning.
	 * Used when transitioning levels or restarting the game.
	 */
	resetTransportPosition(): void {
		Tone.Transport.position = 0
	}

	/**
	 * Check if the Transport is currently playing.
	 */
	getIsPlaying(): boolean {
		return this.isPlaying
	}

	updateBpm(bpm: number): void {
		Tone.Transport.bpm.value = bpm
	}

	setInstrument(name?: InstrumentName): void {
		if (!this.synth) return
		const preset = getInstrumentPreset(name)
		this.synth.set({
			oscillator: { type: preset.oscillatorType },
			envelope: preset.envelope,
		})
		this.synth.volume.value = preset.volume
		this.currentInstrument = name || 'piano'
		this.sparkleOctaveOffset = preset.sparkleOctaveOffset
	}

	playNote(lane: number): void {
		if (!this.initialized || !this.synth || this.muted) return

		const pitch = LANE_PITCHES[lane]
		if (pitch) {
			this.synth.triggerAttackRelease(pitch, '8n')
		}
	}

	playPerfect(lane: number): void {
		if (!this.initialized || !this.synth || this.muted) return

		// Play the note with a sparkle effect (higher octave accent)
		const basePitch = LANE_PITCHES[lane]
		if (basePitch) {
			this.synth.triggerAttackRelease(basePitch, '8n')
			// Add sparkle with higher octave
			const highPitch = transposeOctave(basePitch, this.sparkleOctaveOffset)
			setTimeout(() => {
				if (this.synth && !this.muted) {
					this.synth.triggerAttackRelease(highPitch, '16n', undefined, 0.3)
				}
			}, 50)
		}
	}

	// New melodic note methods for the Song System

	/**
	 * Play a specific pitch for a melodic note hit
	 */
	playMelodicNote(pitch: string): void {
		if (!this.initialized || !this.synth || this.muted) return
		this.synth.triggerAttackRelease(pitch, '8n')
	}

	/**
	 * Play a melodic note with sparkle effect for perfect hits
	 */
	playMelodicNotePerfect(pitch: string): void {
		if (!this.initialized || !this.synth || this.muted) return

		// Play the base note
		this.synth.triggerAttackRelease(pitch, '8n')

		// Add sparkle with higher octave
		const highPitch = transposeOctave(pitch, this.sparkleOctaveOffset)
		setTimeout(() => {
			if (this.synth && !this.muted) {
				this.synth.triggerAttackRelease(highPitch, '16n', undefined, 0.3)
			}
		}, 50)
	}

	// ── Sustained note methods for hold notes ──

	/**
	 * Start a sustained note (holds until explicitly released)
	 */
	startSustainedNote(pitch: string): void {
		if (!this.initialized || !this.synth || this.muted) return
		if (this.sustainedNotes.has(pitch)) return // already sustained

		this.synth.triggerAttack(pitch)
		this.sustainedNotes.set(pitch, true)
	}

	/**
	 * Stop a sustained note
	 */
	stopSustainedNote(pitch: string): void {
		if (!this.initialized || !this.synth) return
		if (!this.sustainedNotes.has(pitch)) return

		this.synth.triggerRelease(pitch)
		this.sustainedNotes.delete(pitch)
	}

	/**
	 * Release all currently sustained notes (for pause/game-over/level-up)
	 */
	releaseAllSustainedNotes(): void {
		if (!this.initialized || !this.synth) return

		this.sustainedNotes.forEach((_, pitch) => {
			this.synth!.triggerRelease(pitch)
		})
		this.sustainedNotes.clear()
	}

	playCountdownTick(): void {
		if (!this.initialized || !this.synth || this.muted) return
		this.synth.triggerAttackRelease('G5', '16n', undefined, 0.5)
	}

	playCountdownGo(): void {
		if (!this.initialized || !this.synth || this.muted) return
		this.synth.triggerAttackRelease(['C5', 'E5', 'G5'], '8n', undefined, 0.6)
	}

	playMiss(): void {
		if (!this.initialized || !this.synth || this.muted) return

		// Play a dissonant sound for miss
		this.synth.triggerAttackRelease(['C3', 'Db3'], '16n', undefined, 0.3)
	}

	playCombo(): void {
		if (!this.initialized || !this.synth || this.muted) return

		// Play ascending arpeggio for combo milestone
		const notes = ['C5', 'E5', 'G5', 'C6']
		notes.forEach((note, i) => {
			setTimeout(() => {
				if (this.synth && !this.muted) {
					this.synth.triggerAttackRelease(note, '16n', undefined, 0.4)
				}
			}, i * 50)
		})
	}

	setMuted(muted: boolean): void {
		this.muted = muted
	}

	isMuted(): boolean {
		return this.muted
	}

	dispose(): void {
		this.releaseAllSustainedNotes()
		this.stopBackgroundBeat()
		if (this.synth) {
			this.synth.dispose()
			this.synth = null
		}
		if (this.drumSynth) {
			this.drumSynth.dispose()
			this.drumSynth = null
		}
		if (this.hiHatSynth) {
			this.hiHatSynth.dispose()
			this.hiHatSynth = null
		}
		if (this.snareSynth) {
			this.snareSynth.dispose()
			this.snareSynth = null
		}
		this.initialized = false
	}
}

// Singleton instance
export const audioManager = new AudioManager()
