import {
	Scene,
	Points,
	BufferGeometry,
	Float32BufferAttribute,
	PointsMaterial,
	Mesh,
	PlaneGeometry,
	MeshBasicMaterial,
	EdgesGeometry,
	LineSegments,
	LineBasicMaterial,
	TetrahedronGeometry,
	OctahedronGeometry,
	Color,
	DoubleSide,
} from 'three'
import {
	HIGHWAY_3D,
	DEFAULT_LANE_COLORS,
	BACKGROUND_ANIMATIONS,
	type BackgroundAnimationType,
} from '../constants'

const LANE_COLORS = [
	DEFAULT_LANE_COLORS.lane0,
	DEFAULT_LANE_COLORS.lane1,
	DEFAULT_LANE_COLORS.lane2,
	DEFAULT_LANE_COLORS.lane3,
]

function randomLaneColor(): string {
	return LANE_COLORS[Math.floor(Math.random() * LANE_COLORS.length)]
}

// ── Stars ──

interface StarState {
	baseIndex: number // index into positions array (×3)
	speed: number
	twinkleSpeed: number
}

// ── Rays ──

interface RayState {
	mesh: Mesh
	angle: number
	speed: number
	color: Color
}

// ── Shapes ──

interface ShapeState {
	line: LineSegments
	x: number
	y: number
	speed: number
	rotationSpeed: number
}

// ── Waves ──

interface WaveState {
	mesh: Mesh
	baseY: number
	speed: number
	opacity: number
}

export class BackgroundFX {
	private type: BackgroundAnimationType
	private disposables: { dispose: () => void }[] = []

	// Stars
	private starsGeometry: BufferGeometry | null = null
	private starsMaterial: PointsMaterial | null = null
	private starsPoints: Points | null = null
	private stars: StarState[] = []

	// Rays
	private rays: RayState[] = []

	// Shapes
	private shapes: ShapeState[] = []

	// Waves
	private waves: WaveState[] = []

	constructor(private scene: Scene) {
		this.type =
			BACKGROUND_ANIMATIONS[
				Math.floor(Math.random() * BACKGROUND_ANIMATIONS.length)
			]
		this.init()
	}

	private init() {
		switch (this.type) {
			case 'stars':
				this.initStars()
				break
			case 'rays':
				this.initRays()
				break
			case 'shapes':
				this.initShapes()
				break
			case 'waves':
				this.initWaves()
				break
		}
	}

	// ── Stars: Points geometry drifting in -Z ──

	private initStars() {
		const count = 40
		const positions = new Float32Array(count * 3)
		const colors = new Float32Array(count * 3)
		const spreadX = HIGHWAY_3D.roadWidth * 2.5
		const spreadZ = HIGHWAY_3D.roadLength * 1.2

		for (let i = 0; i < count; i++) {
			positions[i * 3] = (Math.random() - 0.5) * spreadX
			positions[i * 3 + 1] = 0.5 + Math.random() * 6
			positions[i * 3 + 2] = -Math.random() * spreadZ + HIGHWAY_3D.hitZoneZ

			const c = new Color(randomLaneColor())
			colors[i * 3] = c.r
			colors[i * 3 + 1] = c.g
			colors[i * 3 + 2] = c.b

			this.stars.push({
				baseIndex: i * 3,
				speed: 0.3 + Math.random() * 0.5,
				twinkleSpeed: 1 + Math.random() * 3,
			})
		}

		this.starsGeometry = new BufferGeometry()
		this.starsGeometry.setAttribute(
			'position',
			new Float32BufferAttribute(positions, 3)
		)
		this.starsGeometry.setAttribute(
			'color',
			new Float32BufferAttribute(colors, 3)
		)

		this.starsMaterial = new PointsMaterial({
			size: 0.25,
			sizeAttenuation: true,
			transparent: true,
			opacity: 0.7,
			vertexColors: true,
			depthWrite: false,
		})

		this.starsPoints = new Points(this.starsGeometry, this.starsMaterial)
		this.starsPoints.renderOrder = -1
		this.scene.add(this.starsPoints)
		this.disposables.push(this.starsGeometry, this.starsMaterial)
	}

	// ── Rays: thin triangular planes from far vanishing point ──

	private initRays() {
		const count = 10
		for (let i = 0; i < count; i++) {
			const angle = (i / count) * Math.PI * 2
			const width = 0.4 + Math.random() * 0.6
			const c = new Color(randomLaneColor())
			const geo = new PlaneGeometry(width, HIGHWAY_3D.roadLength * 1.5)
			const mat = new MeshBasicMaterial({
				color: c,
				transparent: true,
				opacity: 0.08,
				side: DoubleSide,
				depthWrite: false,
			})
			const mesh = new Mesh(geo, mat)
			mesh.renderOrder = -1
			// Place at far end, tilted
			mesh.position.set(0, 2, -HIGHWAY_3D.roadLength * 0.6)
			mesh.rotation.z = angle
			this.scene.add(mesh)
			this.rays.push({
				mesh,
				angle,
				speed: 0.0002 + Math.random() * 0.0003,
				color: c,
			})
			this.disposables.push(geo, mat)
		}
	}

	// ── Shapes: wireframe triangles/diamonds/hexagons ──

	private initShapes() {
		const count = 18
		const spreadX = HIGHWAY_3D.roadWidth * 1.5
		const spreadZ = HIGHWAY_3D.roadLength

		for (let i = 0; i < count; i++) {
			const shapeType = i % 3 // 0=tetra, 1=octa, 2=tetra (varied)
			const size = 0.2 + Math.random() * 0.3
			const baseGeo =
				shapeType === 1
					? new OctahedronGeometry(size)
					: new TetrahedronGeometry(size)
			const edgesGeo = new EdgesGeometry(baseGeo)
			const mat = new LineBasicMaterial({
				color: new Color(randomLaneColor()),
				transparent: true,
				opacity: 0.25,
				depthWrite: false,
			})
			const line = new LineSegments(edgesGeo, mat)
			line.renderOrder = -1

			const x = (Math.random() - 0.5) * spreadX
			const y = -2 + Math.random() * 8
			const z = -Math.random() * spreadZ + HIGHWAY_3D.hitZoneZ

			line.position.set(x, y, z)
			this.scene.add(line)

			this.shapes.push({
				line,
				x,
				y,
				speed: 0.3 + Math.random() * 0.4,
				rotationSpeed: (Math.random() - 0.5) * 0.04,
			})

			this.disposables.push(baseGeo, edgesGeo, mat)
		}
	}

	// ── Waves: sine-deformed horizontal strips ──

	private initWaves() {
		const count = 6
		const roadW = HIGHWAY_3D.roadWidth * 1.5
		const segW = 40

		for (let i = 0; i < count; i++) {
			const geo = new PlaneGeometry(roadW, 0.04, segW, 1)
			geo.rotateX(-Math.PI / 2)
			const c = new Color(LANE_COLORS[i % 4])
			const mat = new MeshBasicMaterial({
				color: c,
				transparent: true,
				opacity: 0.12 + Math.random() * 0.08,
				side: DoubleSide,
				depthWrite: false,
			})
			const mesh = new Mesh(geo, mat)
			mesh.renderOrder = -1
			const z = HIGHWAY_3D.hitZoneZ - (i / count) * HIGHWAY_3D.roadLength * 0.8
			mesh.position.set(0, 0.3 + Math.random() * 2, z)
			this.scene.add(mesh)

			this.waves.push({
				mesh,
				baseY: mesh.position.y,
				speed: 0.4 + Math.random() * 0.3,
				opacity: 0.12 + Math.random() * 0.08,
			})

			this.disposables.push(geo, mat)
		}
	}

	// ── Per-frame update ──

	update(delta: number, elapsedTime: number, bpm: number) {
		const beatPhase = ((elapsedTime / (60000 / bpm)) % 1) * Math.PI * 2

		switch (this.type) {
			case 'stars':
				this.updateStars(delta, elapsedTime)
				break
			case 'rays':
				this.updateRays(elapsedTime, beatPhase)
				break
			case 'shapes':
				this.updateShapes(delta)
				break
			case 'waves':
				this.updateWaves(delta, elapsedTime, beatPhase)
				break
		}
	}

	private updateStars(delta: number, elapsedTime: number) {
		if (!this.starsGeometry || !this.starsMaterial) return

		const positions = this.starsGeometry.attributes
			.position as Float32BufferAttribute
		const arr = positions.array as Float32Array

		for (const star of this.stars) {
			const i = star.baseIndex
			// drift in -Z (toward camera)
			arr[i + 2] += star.speed * delta
			if (arr[i + 2] > HIGHWAY_3D.hitZoneZ + 2) {
				arr[i + 2] = HIGHWAY_3D.hitZoneZ - HIGHWAY_3D.roadLength * 1.2
				arr[i] = (Math.random() - 0.5) * HIGHWAY_3D.roadWidth * 2.5
			}
			// Per-star vertical shimmer for a twinkling effect
			arr[i + 1] += Math.sin(elapsedTime * 0.001 * star.twinkleSpeed) * 0.003
		}
		positions.needsUpdate = true

		// Gentle global pulse
		this.starsMaterial.opacity = 0.5 + Math.sin(elapsedTime * 0.002) * 0.2
	}

	private updateRays(elapsedTime: number, beatPhase: number) {
		for (const ray of this.rays) {
			ray.mesh.rotation.z = ray.angle + elapsedTime * ray.speed
			const mat = ray.mesh.material as MeshBasicMaterial
			mat.opacity = 0.06 + Math.sin(beatPhase) * 0.04
		}
	}

	private updateShapes(delta: number) {
		for (const shape of this.shapes) {
			shape.line.position.y += shape.speed * delta
			shape.line.rotation.x += shape.rotationSpeed
			shape.line.rotation.y += shape.rotationSpeed * 0.7

			if (shape.line.position.y > 8) {
				shape.line.position.y = -2
				shape.line.position.x =
					(Math.random() - 0.5) * HIGHWAY_3D.roadWidth * 1.5
			}
		}
	}

	private updateWaves(delta: number, elapsedTime: number, beatPhase: number) {
		for (const wave of this.waves) {
			wave.mesh.position.y += wave.speed * delta * 0.3
			if (wave.mesh.position.y > 6) {
				wave.mesh.position.y = -1
			}

			// Sine deformation
			const geo = wave.mesh.geometry as PlaneGeometry
			const pos = geo.attributes.position
			const arr = pos.array as Float32Array
			for (let i = 0; i < pos.count; i++) {
				const x = arr[i * 3]
				arr[i * 3 + 1] =
					Math.sin(x * 0.8 + elapsedTime * 0.003) * 0.15 +
					Math.sin(x * 0.5 - elapsedTime * 0.002) * 0.08
			}
			pos.needsUpdate = true

			// BPM pulse
			const mat = wave.mesh.material as MeshBasicMaterial
			mat.opacity = wave.opacity * (0.6 + Math.sin(beatPhase) * 0.4)
		}
	}

	dispose() {
		for (const d of this.disposables) {
			d.dispose()
		}
		if (this.starsPoints) {
			this.scene.remove(this.starsPoints)
		}
		for (const ray of this.rays) {
			this.scene.remove(ray.mesh)
		}
		for (const shape of this.shapes) {
			this.scene.remove(shape.line)
		}
		for (const wave of this.waves) {
			this.scene.remove(wave.mesh)
		}
		this.disposables = []
		this.stars = []
		this.rays = []
		this.shapes = []
		this.waves = []
	}
}
