import React, { useEffect, useRef, useCallback } from 'react'
import { Vector3 } from 'three'
import { SceneManager } from './engine/SceneManager'
import { HighwayBuilder } from './engine/HighwayBuilder'
import { NoteManager } from './engine/NoteManager'
import { BackgroundFX } from './engine/BackgroundFX'
import { audioManager } from './utils/audioManager'
import { hapticManager } from '../utils/hapticManager'
import type { Note, HitEffect } from './types'
import type { Song, Difficulty } from './songs'
import type { DrumPattern } from './songs/songTypes'
import { getSongForLevel, resetSongShuffle, TOTAL_LEVELS } from './songs'
import {
	HIGHWAY_3D,
	CANVAS_HEIGHT,
	LANE_COUNT,
	LANE_KEYS,
	DEFAULT_LANE_COLORS,
	PERFECT_WINDOW,
	GOOD_WINDOW,
	BAD_WINDOW,
	INPUT_LENIENCY_BUFFER,
	PERFECT_POINTS,
	GOOD_POINTS,
	BAD_POINTS,
	MAX_COMBO_MULTIPLIER,
	SPEED_BY_DIFFICULTY,
	DIFFICULTY_NAMES,
	COUNTDOWN_DURATION,
	VAMOS_DURATION,
	PERSPECTIVE_HIT_OFFSET,
	HOLD_NOTE_MIN_BEATS,
	HOLD_TICK_INTERVAL_MS,
	HOLD_COMPLETION_THRESHOLD,
	HOLD_BASE_BONUS,
	HOLD_TICK_POINTS,
} from './constants'

const LANE_COLOR_ARRAY = [
	DEFAULT_LANE_COLORS.lane0,
	DEFAULT_LANE_COLORS.lane1,
	DEFAULT_LANE_COLORS.lane2,
	DEFAULT_LANE_COLORS.lane3,
]

// ── Types ──

export interface GameUIState {
	points: number
	combo: number
	maxCombo: number
	level: number
	lives: number
	perfectCount: number
	goodCount: number
	badCount: number
	missCount: number
	hitEffects: HitEffect[]
	isCountingDown: boolean
	countdownValue: string // '3','2','1','¡VAMOS!' or ''
	songTitle: string
	difficultyName: string
	displayName: string
	showLevelUp: boolean
	nextSongTitle: string
	nextSongArtist: string
	nextDifficultyName: string
	nextCycle: number
	gamePaused: boolean
	laneScreenPositions: number[] // projected X percentages for each lane
}

interface RhythmHighway3DCoreProps {
	brandColor: string
	initialLives: number
	onGameOver: (points: number) => void
	onPointsChange: (points: number) => void
	onLivesChange: (lives: number) => void
	onUIStateChange: (state: GameUIState) => void
	onTogglePause: () => void
	gamePaused: boolean
	quitRequested: boolean
	maxPoints?: number
}

interface LevelConfig {
	song: Song
	difficulty: Difficulty
	track: DrumPattern
	speedMultiplier: number
	cycle: number
	displayName: string
}

const RhythmHighway3DCore: React.FC<RhythmHighway3DCoreProps> = ({
	brandColor,
	initialLives,
	onGameOver,
	onPointsChange,
	onLivesChange,
	onUIStateChange,
	onTogglePause,
	gamePaused,
	quitRequested,
	maxPoints,
}) => {
	const containerRef = useRef<HTMLDivElement>(null)
	const engineRef = useRef<{
		scene: SceneManager
		highway: HighwayBuilder
		notes: NoteManager
		bg: BackgroundFX
	} | null>(null)

	// Game state refs (avoid closures capturing stale state)
	const notesRef = useRef<Note[]>([])
	const hitEffectsRef = useRef<HitEffect[]>([])
	const pointsRef = useRef(0)
	const comboRef = useRef(0)
	const maxComboRef = useRef(0)
	const livesRef = useRef(initialLives)
	const levelRef = useRef(1)
	const lastBeatRef = useRef(-1)
	const noteIdCounterRef = useRef(0)
	const songNoteIndexRef = useRef(0)
	const songLoopCountRef = useRef(0)
	const loopOffsetRef = useRef(0)
	const lastKeyReleaseTimeRef = useRef<Record<number, number>>({})
	const waitingForNotesClearRef = useRef(false)
	const countdownRef = useRef<number>(0)
	const countdownStartTimeRef = useRef<number>(0)
	const currentConfigRef = useRef<LevelConfig | null>(null)
	const nextLevelConfigRef = useRef<LevelConfig | null>(null)
	const perfectCountRef = useRef(0)
	const goodCountRef = useRef(0)
	const badCountRef = useRef(0)
	const missCountRef = useRef(0)
	const audioInitializedRef = useRef(false)
	const gamePausedRef = useRef(false)
	const showLevelUpRef = useRef(false)
	const levelUpTimeoutRef = useRef<NodeJS.Timeout | null>(null)
	const isCountingDownRef = useRef(false)
	const gameOverRef = useRef(false)
	const maxPointsRef = useRef(maxPoints)
	const lastCountdownNumberRef = useRef(-1)
	const laneScreenPositionsRef = useRef<number[]>([25, 41.67, 58.33, 75])

	// Hold note tracking
	const heldLanesRef = useRef<Record<number, boolean>>({
		0: false,
		1: false,
		2: false,
		3: false,
	})
	const heldLaneNoteRef = useRef<Record<number, number | null>>({
		0: null,
		1: null,
		2: null,
		3: null,
	})

	// Keep refs in sync
	useEffect(() => {
		maxPointsRef.current = maxPoints
	}, [maxPoints])

	useEffect(() => {
		gamePausedRef.current = gamePaused
		if (gamePaused || quitRequested) {
			audioManager.pauseBackgroundBeat()
			audioManager.releaseAllSustainedNotes()
		} else {
			audioManager.resumeBackgroundBeat()
			// Re-trigger sustained audio for any notes still being held
			for (let lane = 0; lane < 4; lane++) {
				const noteId = heldLaneNoteRef.current[lane]
				if (noteId !== null && heldLanesRef.current[lane]) {
					const note = notesRef.current.find(
						n => n.id === noteId && n.holdState === 'holding'
					)
					if (note?.pitch) {
						audioManager.startSustainedNote(note.pitch)
					}
				}
			}
		}
	}, [gamePaused, quitRequested])

	const getLevelConfig = useCallback((lvl: number): LevelConfig => {
		const { song, cycle, speedMultiplier } = getSongForLevel(lvl)
		const difficulty = song.metadata.difficulty
		const difficultyName = DIFFICULTY_NAMES[difficulty] || difficulty
		return {
			song,
			difficulty,
			track: song.background.drumPattern,
			speedMultiplier,
			cycle,
			displayName:
				cycle > 0
					? `${song.metadata.title} (${difficultyName}) x${cycle + 1}`
					: `${song.metadata.title} (${difficultyName})`,
		}
	}, [])

	// Push UI state to parent (called in animation loop)
	const pushUI = useCallback(() => {
		const cfg = currentConfigRef.current
		const nextCfg = nextLevelConfigRef.current

		let countdownValue = ''
		if (isCountingDownRef.current && countdownRef.current > 0) {
			const elapsed = (performance.now() - countdownStartTimeRef.current) / 1000
			if (elapsed < COUNTDOWN_DURATION) {
				countdownValue = String(Math.ceil(COUNTDOWN_DURATION - elapsed))
			} else {
				countdownValue = '¡VAMOS!'
			}
		}

		onUIStateChange({
			points: pointsRef.current,
			combo: comboRef.current,
			maxCombo: maxComboRef.current,
			level: levelRef.current,
			lives: livesRef.current,
			perfectCount: perfectCountRef.current,
			goodCount: goodCountRef.current,
			badCount: badCountRef.current,
			missCount: missCountRef.current,
			hitEffects: [...hitEffectsRef.current],
			isCountingDown: isCountingDownRef.current,
			countdownValue,
			songTitle: cfg?.song.metadata.title || '',
			difficultyName: DIFFICULTY_NAMES[cfg?.difficulty || ''] || '',
			displayName: cfg?.displayName || '',
			showLevelUp: showLevelUpRef.current,
			nextSongTitle: nextCfg?.song.metadata.title || '',
			nextSongArtist: nextCfg?.song.metadata.artist || '',
			nextDifficultyName: DIFFICULTY_NAMES[nextCfg?.difficulty || ''] || '',
			nextCycle: nextCfg?.cycle || 0,
			gamePaused: gamePausedRef.current,
			laneScreenPositions: laneScreenPositionsRef.current,
		})
	}, [onUIStateChange])

	// ── Hold release handler ──
	const handleHoldRelease = useCallback(
		(lane: number) => {
			const noteId = heldLaneNoteRef.current[lane]
			if (noteId === null) return

			const note = notesRef.current.find(n => n.id === noteId)
			if (!note || note.holdState !== 'holding') {
				heldLaneNoteRef.current[lane] = null
				return
			}

			const engine = engineRef.current
			const now = Date.now()

			// Stop sustained audio
			if (note.pitch) {
				audioManager.stopSustainedNote(note.pitch)
			}

			// Calculate how much of the hold was completed
			const holdStartTime = note.holdStartTime || now
			const elapsed = now - holdStartTime
			const cfg = currentConfigRef.current
			if (!cfg) return

			// Convert holdDurationBeats to time in ms
			const beatDurationMs = 60000 / cfg.song.metadata.bpm
			const requiredDurationMs = note.holdDurationBeats * beatDurationMs
			const completionRatio =
				requiredDurationMs > 0 ? elapsed / requiredDurationMs : 1

			if (completionRatio >= HOLD_COMPLETION_THRESHOLD) {
				// Successful hold completion
				note.holdState = 'completed'
				const multiplier = Math.min(comboRef.current + 1, MAX_COMBO_MULTIPLIER)
				pointsRef.current += HOLD_BASE_BONUS * multiplier
				onPointsChange(pointsRef.current)
				if (engine) engine.notes.triggerHoldComplete(noteId)
				hapticManager.perfectHit()
			} else {
				// Early release - partial credit, combo resets
				note.holdState = 'dropped'
				comboRef.current = 0
				if (engine) engine.notes.triggerHoldDrop(noteId)
			}

			note.hit = true
			note.hitTime = now
			heldLaneNoteRef.current[lane] = null

			// Check maxPoints cap
			if (maxPointsRef.current && pointsRef.current >= maxPointsRef.current) {
				pointsRef.current = maxPointsRef.current
				onPointsChange(maxPointsRef.current)
				gameOverRef.current = true
				audioManager.stopBackgroundBeat()
				audioManager.releaseAllSustainedNotes()
				onGameOver(maxPointsRef.current)
			}
		},
		[onPointsChange, onGameOver]
	)

	// ── Hit detection ──
	const checkHit = useCallback(
		(lane: number) => {
			if (
				gamePausedRef.current ||
				countdownRef.current > 0 ||
				gameOverRef.current
			)
				return

			// If there's already a hold note active in this lane, auto-release it first
			if (heldLaneNoteRef.current[lane] !== null) {
				handleHoldRelease(lane)
			}

			const notes = notesRef.current
			const now = Date.now()
			const engine = engineRef.current
			if (!engine) return

			// In 3D, the hit zone is at Z=0. Distance = |note.z|
			// We convert that Z distance back to a time distance using the
			// same formula as the 2D version: pixel distance → time distance.
			const cfg = currentConfigRef.current
			if (!cfg) return
			const currentSpeed =
				SPEED_BY_DIFFICULTY[cfg.difficulty] * cfg.speedMultiplier

			let closestNote: Note | null = null
			let closestDistZ = Infinity

			for (const note of notes) {
				if (
					note.lane === lane &&
					!note.hit &&
					!note.missed &&
					note.holdState !== 'holding'
				) {
					// Note stores z in note.y (repurposed — see note spawning)
					const noteZ = note.y
					const distZ = Math.abs(
						noteZ - (HIGHWAY_3D.hitZoneZ + PERSPECTIVE_HIT_OFFSET)
					)
					if (distZ < closestDistZ) {
						closestDistZ = distZ
						closestNote = note
					}
				}
			}

			if (!closestNote) {
				hitEffectsRef.current.push({
					id: now,
					lane,
					type: 'miss',
					time: now,
				})
				return
			}

			// Convert world-Z distance to pixel distance, then to time
			const pixelDistance =
				(closestDistZ / HIGHWAY_3D.roadLength) * CANVAS_HEIGHT
			let timeDistance = (pixelDistance / currentSpeed) * (1000 / 60)

			// Input leniency
			const lastReleaseTime = lastKeyReleaseTimeRef.current[lane] || 0
			const timeSinceRelease = now - lastReleaseTime
			if (timeSinceRelease < INPUT_LENIENCY_BUFFER) {
				const leniencyFactor =
					(INPUT_LENIENCY_BUFFER - timeSinceRelease) / INPUT_LENIENCY_BUFFER
				timeDistance = Math.max(
					0,
					timeDistance - timeDistance * 0.3 * leniencyFactor
				)
			}

			if (timeDistance > BAD_WINDOW) return

			// Determine hit type
			let hitType: 'perfect' | 'good' | 'bad'
			if (timeDistance <= PERFECT_WINDOW) {
				hitType = 'perfect'
			} else if (timeDistance <= GOOD_WINDOW) {
				hitType = 'good'
			} else {
				hitType = 'bad'
			}

			closestNote.hitType = hitType

			// ── Hold note: start holding instead of immediate hit ──
			if (closestNote.isHold) {
				closestNote.holdState = 'holding'
				closestNote.holdStartTime = now
				closestNote.lastTickTime = now
				heldLaneNoteRef.current[lane] = closestNote.id

				// Start sustained audio
				if (closestNote.pitch) {
					audioManager.startSustainedNote(closestNote.pitch)
				}

				// Score the initial press (same as regular)
				if (hitType === 'perfect') {
					perfectCountRef.current++
					const multiplier = Math.min(
						comboRef.current + 1,
						MAX_COMBO_MULTIPLIER
					)
					pointsRef.current += PERFECT_POINTS * multiplier
					comboRef.current++
					maxComboRef.current = Math.max(maxComboRef.current, comboRef.current)
					if (comboRef.current % 10 === 0) {
						audioManager.playCombo()
						hapticManager.comboMilestone()
					}
					hapticManager.perfectHit()
				} else if (hitType === 'good') {
					goodCountRef.current++
					const multiplier = Math.min(
						comboRef.current + 1,
						MAX_COMBO_MULTIPLIER
					)
					pointsRef.current += GOOD_POINTS * multiplier
					comboRef.current++
					maxComboRef.current = Math.max(maxComboRef.current, comboRef.current)
					hapticManager.goodHit()
				} else {
					badCountRef.current++
					pointsRef.current += BAD_POINTS
					comboRef.current = 0
					hapticManager.goodHit()
				}

				// Don't set note.hit = true yet (wait for release/completion)
				// But DO trigger the receptor flash and hit effect
				engine.highway.flashReceptor(lane)
				hitEffectsRef.current.push({
					id: now,
					lane,
					type: hitType,
					time: now,
				})
				onPointsChange(pointsRef.current)

				// Check maxPoints cap
				if (maxPointsRef.current && pointsRef.current >= maxPointsRef.current) {
					pointsRef.current = maxPointsRef.current
					onPointsChange(maxPointsRef.current)
					gameOverRef.current = true
					audioManager.stopBackgroundBeat()
					audioManager.releaseAllSustainedNotes()
					onGameOver(maxPointsRef.current)
				}
				return
			}

			// ── Regular tap note ──
			closestNote.hit = true
			closestNote.hitTime = now

			if (hitType === 'perfect') {
				perfectCountRef.current++
				const multiplier = Math.min(comboRef.current + 1, MAX_COMBO_MULTIPLIER)
				pointsRef.current += PERFECT_POINTS * multiplier
				comboRef.current++
				maxComboRef.current = Math.max(maxComboRef.current, comboRef.current)
				if (comboRef.current % 10 === 0) {
					audioManager.playCombo()
					hapticManager.comboMilestone()
				}
				hapticManager.perfectHit()
				if (closestNote.pitch) {
					audioManager.playMelodicNotePerfect(closestNote.pitch)
				} else {
					audioManager.playPerfect(lane)
				}
				engine.notes.triggerHit(closestNote.id, 'perfect')
			} else if (hitType === 'good') {
				goodCountRef.current++
				const multiplier = Math.min(comboRef.current + 1, MAX_COMBO_MULTIPLIER)
				pointsRef.current += GOOD_POINTS * multiplier
				comboRef.current++
				maxComboRef.current = Math.max(maxComboRef.current, comboRef.current)
				hapticManager.goodHit()
				if (closestNote.pitch) {
					audioManager.playMelodicNote(closestNote.pitch)
				} else {
					audioManager.playNote(lane)
				}
				engine.notes.triggerHit(closestNote.id, 'good')
			} else {
				badCountRef.current++
				pointsRef.current += BAD_POINTS
				comboRef.current = 0
				hapticManager.goodHit()
				if (closestNote.pitch) {
					audioManager.playMelodicNote(closestNote.pitch)
				} else {
					audioManager.playNote(lane)
				}
				engine.notes.triggerHit(closestNote.id, 'bad')
			}

			onPointsChange(pointsRef.current)

			// Check maxPoints cap
			if (maxPointsRef.current && pointsRef.current >= maxPointsRef.current) {
				pointsRef.current = maxPointsRef.current
				onPointsChange(maxPointsRef.current)
				gameOverRef.current = true
				audioManager.stopBackgroundBeat()
				onGameOver(maxPointsRef.current)
				return
			}

			hitEffectsRef.current.push({
				id: now,
				lane,
				type: closestNote.hitType!,
				time: now,
			})

			engine.highway.flashReceptor(lane)
		},
		[onPointsChange, onGameOver, handleHoldRelease]
	)

	// ── Keyboard ──
	useEffect(() => {
		const handleKeyDown = (e: KeyboardEvent) => {
			if (e.repeat) return // Ignore held-key repeats
			const key = e.key.toLowerCase()
			const laneIndex = LANE_KEYS.indexOf(key)
			if (laneIndex !== -1 || key === 'p' || key === ' ' || key === 'escape') {
				e.preventDefault()
				e.stopPropagation()
			}
			if (laneIndex !== -1) {
				heldLanesRef.current[laneIndex] = true
				checkHit(laneIndex)
			} else if (key === 'p' || key === ' ') {
				onTogglePause()
			}
		}

		const handleKeyUp = (e: KeyboardEvent) => {
			const key = e.key.toLowerCase()
			const laneIndex = LANE_KEYS.indexOf(key)
			if (laneIndex !== -1) {
				heldLanesRef.current[laneIndex] = false
				lastKeyReleaseTimeRef.current[laneIndex] = Date.now()
				handleHoldRelease(laneIndex)
			}
		}

		document.addEventListener('keydown', handleKeyDown, {
			passive: false,
		})
		document.addEventListener('keyup', handleKeyUp)
		return () => {
			document.removeEventListener('keydown', handleKeyDown)
			document.removeEventListener('keyup', handleKeyUp)
		}
	}, [checkHit, onTogglePause, handleHoldRelease])

	// ── Level up ──
	const triggerLevelUp = useCallback(() => {
		// Clean up any active hold notes
		audioManager.releaseAllSustainedNotes()
		for (let i = 0; i < 4; i++) {
			heldLaneNoteRef.current[i] = null
		}

		// Game completed — player beat all levels
		if (levelRef.current >= TOTAL_LEVELS) {
			audioManager.playCombo()
			hapticManager.levelUp()
			gameOverRef.current = true
			audioManager.stopBackgroundBeat()
			onGameOver(pointsRef.current)
			return
		}

		const nextConfig = getLevelConfig(levelRef.current + 1)
		nextLevelConfigRef.current = nextConfig
		showLevelUpRef.current = true
		gamePausedRef.current = true
		audioManager.playCombo()
		hapticManager.levelUp()

		levelUpTimeoutRef.current = setTimeout(() => {
			const newLevel = levelRef.current + 1
			levelRef.current = newLevel
			showLevelUpRef.current = false
			gamePausedRef.current = false
			songLoopCountRef.current = 0
			songNoteIndexRef.current = 0
			loopOffsetRef.current = 0
			notesRef.current = []
			hitEffectsRef.current = []
			lastBeatRef.current = -1

			const newConfig = nextLevelConfigRef.current!
			currentConfigRef.current = newConfig
			nextLevelConfigRef.current = null

			// Clear 3D notes and hold state
			engineRef.current?.notes.clearAll()
			for (let i = 0; i < 4; i++) {
				heldLaneNoteRef.current[i] = null
			}

			audioManager.stopBackgroundBeat()

			// Set clear colour based on drum pattern
			if (engineRef.current) {
				const track = newConfig.track
				const clearColor =
					track === 'chill'
						? '#0a1a1a'
						: track === 'upbeat'
							? '#1a0a0a'
							: '#0a0a1a'
				engineRef.current.scene.setClearColor(clearColor)
			}

			countdownRef.current = 1
			countdownStartTimeRef.current = performance.now()
			isCountingDownRef.current = true
		}, 2000)
	}, [getLevelConfig, onGameOver])

	// ── Initialise engine + game loop ──
	useEffect(() => {
		if (!containerRef.current) return

		// Initialise audio
		const initAudio = async () => {
			await audioManager.init()
			audioInitializedRef.current = true
		}
		initAudio()
		hapticManager.init()
		resetSongShuffle()

		// Reset game state
		pointsRef.current = 0
		comboRef.current = 0
		maxComboRef.current = 0
		livesRef.current = initialLives
		levelRef.current = 1
		lastBeatRef.current = -1
		noteIdCounterRef.current = 0
		songLoopCountRef.current = 0
		songNoteIndexRef.current = 0
		loopOffsetRef.current = 0
		lastKeyReleaseTimeRef.current = {}
		waitingForNotesClearRef.current = false
		perfectCountRef.current = 0
		goodCountRef.current = 0
		badCountRef.current = 0
		missCountRef.current = 0
		gameOverRef.current = false
		notesRef.current = []
		hitEffectsRef.current = []

		// Initial config
		const initialConfig = getLevelConfig(1)
		currentConfigRef.current = initialConfig

		// Clear colour based on track
		const track = initialConfig.track
		const clearColor =
			track === 'chill' ? '#0a1a1a' : track === 'upbeat' ? '#1a0a0a' : '#0a0a1a'

		// Build engine
		const sceneManager = new SceneManager(containerRef.current, clearColor)
		const highway = new HighwayBuilder()
		highway.build(sceneManager.scene, brandColor)

		const noteManager = new NoteManager(sceneManager.scene)
		const bgFX = new BackgroundFX(sceneManager.scene)

		engineRef.current = {
			scene: sceneManager,
			highway,
			notes: noteManager,
			bg: bgFX,
		}

		// Compute lane screen positions by projecting 3D receptor coords to screen X%
		const computeLaneScreenPositions = () => {
			const positions: number[] = []
			const camera = sceneManager.camera
			for (let i = 0; i < LANE_COUNT; i++) {
				const worldX = highway.getLaneX(i)
				const v = new Vector3(worldX, HIGHWAY_3D.noteY, HIGHWAY_3D.hitZoneZ)
				v.project(camera)
				// v.x is in NDC [-1, 1] → convert to percentage [0, 100]
				positions.push(((v.x + 1) / 2) * 100)
			}
			laneScreenPositionsRef.current = positions
		}

		computeLaneScreenPositions()
		sceneManager.onResize(() => computeLaneScreenPositions())

		// Start countdown
		audioManager.resetTransportPosition()
		countdownRef.current = 1
		countdownStartTimeRef.current = performance.now()
		isCountingDownRef.current = true

		// UI state polling (50ms like penalty-shootout-3d)
		const uiInterval = setInterval(() => pushUI(), 50)

		// ── Per-frame update ──
		sceneManager.onUpdate((delta: number) => {
			if (gamePausedRef.current || gameOverRef.current) return

			const now = Date.now()
			const currentTime = performance.now()

			// ── Countdown ──
			if (countdownRef.current > 0) {
				const elapsed = (currentTime - countdownStartTimeRef.current) / 1000
				const totalDuration = COUNTDOWN_DURATION + VAMOS_DURATION

				if (elapsed >= totalDuration) {
					countdownRef.current = 0
					isCountingDownRef.current = false
					const cfg = currentConfigRef.current!
					const song = cfg.song
					audioManager.resetTransportPosition()
					audioManager.setInstrument(song.background.instrument)
					if (song.background.drumPattern !== 'none') {
						// Calculate travel delay: time for a note to go from spawn to hit zone
						const noteSpeed =
							SPEED_BY_DIFFICULTY[cfg.difficulty] * cfg.speedMultiplier
						const worldSpeed =
							(noteSpeed / CANVAS_HEIGHT) * HIGHWAY_3D.roadLength * 60
						const travelDelay =
							Math.abs(HIGHWAY_3D.spawnZ - HIGHWAY_3D.hitZoneZ) / worldSpeed
						const beatsPerMeasure = song.background.beatsPerMeasure ?? 4

						audioManager.startBackgroundBeat(
							song.metadata.bpm,
							song.background.drumPattern as 'chill' | 'default' | 'upbeat',
							cfg.cycle,
							travelDelay,
							beatsPerMeasure
						)
					} else {
						// No drums, but still need Transport running for note timing
						const noteSpeed =
							SPEED_BY_DIFFICULTY[cfg.difficulty] * cfg.speedMultiplier
						const worldSpeed =
							(noteSpeed / CANVAS_HEIGHT) * HIGHWAY_3D.roadLength * 60
						const travelDelay =
							Math.abs(HIGHWAY_3D.spawnZ - HIGHWAY_3D.hitZoneZ) / worldSpeed
						audioManager.startTransportOnly(song.metadata.bpm, travelDelay)
					}
				} else {
					// Play countdown sounds on number transitions
					if (elapsed < COUNTDOWN_DURATION) {
						const remaining = Math.ceil(COUNTDOWN_DURATION - elapsed)
						if (remaining !== lastCountdownNumberRef.current) {
							lastCountdownNumberRef.current = remaining
							audioManager.playCountdownTick()
						}
					} else if (lastCountdownNumberRef.current !== 0) {
						lastCountdownNumberRef.current = 0
						audioManager.playCountdownGo()
					}

					// Just update visuals during countdown
					const cfg = currentConfigRef.current!
					highway.updateBeatMarkers(0, cfg.song.metadata.bpm)
					highway.updateReceptors(delta)
					bgFX.update(delta, 0, cfg.song.metadata.bpm)
					return
				}
			}

			const config = currentConfigRef.current!
			const song = config.song
			const currentBpm = song.metadata.bpm
			const currentBeatDuration = 60000 / currentBpm
			const currentNoteSpeed =
				SPEED_BY_DIFFICULTY[config.difficulty] * config.speedMultiplier

			// Transport time for note spawning
			const transportTime = audioManager.getTransportTime()
			const absoluteBeat = transportTime / currentBeatDuration

			const loopStart = song.loop?.startBeat ?? 0
			const loopEnd =
				song.loop?.endBeat ?? Math.max(...song.notes.map(n => n.beat)) + 4
			const loopLength = loopEnd - loopStart
			const currentBeat = absoluteBeat - loopOffsetRef.current
			let spawnBeat = currentBeat

			if (
				lastBeatRef.current > 0 &&
				currentBeat >= loopEnd &&
				lastBeatRef.current < loopEnd
			) {
				songLoopCountRef.current++
				const loopsNeeded = song.loop?.count || 1

				if (songLoopCountRef.current >= loopsNeeded) {
					waitingForNotesClearRef.current = true
					audioManager.stopBackgroundBeat()
				} else {
					loopOffsetRef.current += loopLength
					songNoteIndexRef.current = song.notes.findIndex(
						n => n.beat >= loopStart
					)
					if (songNoteIndexRef.current === -1) songNoteIndexRef.current = 0
					spawnBeat = loopStart
					lastBeatRef.current = loopStart - 0.1
				}
			}

			// Check notes cleared for level up
			if (waitingForNotesClearRef.current) {
				const activeNotes = notesRef.current.filter(n => !n.hit && !n.missed)
				if (activeNotes.length === 0) {
					waitingForNotesClearRef.current = false
					setTimeout(() => triggerLevelUp(), 100)
				}
			}

			// ── Spawn notes ──
			while (songNoteIndexRef.current < song.notes.length) {
				const noteData = song.notes[songNoteIndexRef.current]
				if (noteData.beat <= spawnBeat) {
					const noteId = noteIdCounterRef.current++

					// Determine if this is a hold note based on duration
					let isHold = false
					let holdDurationBeats = 0
					let holdDurationZ = 0
					if (noteData.duration && noteData.duration > 0) {
						const durationBeats = noteData.duration / (60 / currentBpm)
						if (durationBeats >= HOLD_NOTE_MIN_BEATS) {
							isHold = true
							holdDurationBeats = durationBeats
							// Convert beat duration to Z-units
							const beatsToSeconds = durationBeats * (60 / currentBpm)
							const worldSpeedForCalc =
								(currentNoteSpeed / CANVAS_HEIGHT) * HIGHWAY_3D.roadLength * 60
							holdDurationZ = beatsToSeconds * worldSpeedForCalc
						}
					}

					// We store the Z position in note.y (reusing the 2D field)
					notesRef.current.push({
						id: noteId,
						lane: noteData.lane,
						y: HIGHWAY_3D.spawnZ, // Z position
						speed: currentNoteSpeed,
						hit: false,
						missed: false,
						pitch: noteData.pitch,
						isHold,
						holdDurationBeats,
						holdDurationZ,
						holdState: 'none',
						holdProgress: 0,
					})
					noteManager.spawn(noteId, noteData.lane, isHold, holdDurationZ)
					songNoteIndexRef.current++
				} else {
					break
				}
			}
			lastBeatRef.current = currentBeat

			// ── Move / cull notes ──
			// Convert pixel-based speed to world-Z speed
			// original: pixels/frame at 60fps → we need Z units / second
			const worldSpeed =
				(currentNoteSpeed / CANVAS_HEIGHT) * HIGHWAY_3D.roadLength * 60

			notesRef.current = notesRef.current.filter(note => {
				if (note.hit) {
					return now - (note.hitTime || 0) < 200
				}

				// ── Per-frame hold processing ──
				if (note.holdState === 'holding') {
					// Move the note forward
					const dz = worldSpeed * delta
					note.y += dz
					noteManager.moveNote(note.id, dz)

					const isBeingHeld = heldLanesRef.current[note.lane]

					// Update beam visual
					noteManager.updateHoldBeam(note.id, note.y, isBeingHeld)

					// Safety check: if player released key, handle release
					if (!isBeingHeld) {
						// Player released — finalize
						if (note.pitch) {
							audioManager.stopSustainedNote(note.pitch)
						}
						const holdStartTime = note.holdStartTime || now
						const elapsed = now - holdStartTime
						const beatDurationMs = 60000 / currentBpm
						const requiredMs = note.holdDurationBeats * beatDurationMs
						const ratio = requiredMs > 0 ? elapsed / requiredMs : 1

						if (ratio >= HOLD_COMPLETION_THRESHOLD) {
							note.holdState = 'completed'
							const multiplier = Math.min(
								comboRef.current + 1,
								MAX_COMBO_MULTIPLIER
							)
							pointsRef.current += HOLD_BASE_BONUS * multiplier
							noteManager.triggerHoldComplete(note.id)
							hapticManager.perfectHit()
						} else {
							note.holdState = 'dropped'
							comboRef.current = 0
							noteManager.triggerHoldDrop(note.id)
						}
						note.hit = true
						note.hitTime = now
						heldLaneNoteRef.current[note.lane] = null
						onPointsChange(pointsRef.current)
						return true
					}

					// Award tick points every HOLD_TICK_INTERVAL_MS
					const lastTick = note.lastTickTime || now
					if (now - lastTick >= HOLD_TICK_INTERVAL_MS) {
						const multiplier = Math.min(
							comboRef.current + 1,
							MAX_COMBO_MULTIPLIER
						)
						pointsRef.current += HOLD_TICK_POINTS * multiplier
						note.lastTickTime = now
						onPointsChange(pointsRef.current)

						// Check maxPoints cap
						if (
							maxPointsRef.current &&
							pointsRef.current >= maxPointsRef.current
						) {
							pointsRef.current = maxPointsRef.current
							onPointsChange(maxPointsRef.current)
							gameOverRef.current = true
							audioManager.stopBackgroundBeat()
							audioManager.releaseAllSustainedNotes()
							onGameOver(maxPointsRef.current)
						}
					}

					// Auto-complete when beam fully passes through hit zone
					const beamTailZ = note.y - note.holdDurationZ
					if (beamTailZ > HIGHWAY_3D.hitZoneZ + 0.5) {
						if (note.pitch) {
							audioManager.stopSustainedNote(note.pitch)
						}
						note.holdState = 'completed'
						const multiplier = Math.min(
							comboRef.current + 1,
							MAX_COMBO_MULTIPLIER
						)
						pointsRef.current += HOLD_BASE_BONUS * multiplier
						noteManager.triggerHoldComplete(note.id)
						hapticManager.perfectHit()
						note.hit = true
						note.hitTime = now
						heldLaneNoteRef.current[note.lane] = null
						onPointsChange(pointsRef.current)
					}

					return true // Keep hold notes alive
				}

				// Increment Z toward hit zone (positive direction)
				const dz = worldSpeed * delta
				note.y += dz // note.y = z position
				noteManager.moveNote(note.id, dz)

				// Miss detection: passed the hit zone
				// For hold notes with holdState 'none' (never pressed), they miss like regular notes
				if (note.y > HIGHWAY_3D.hitZoneZ + 1 && !note.missed) {
					note.missed = true
					missCountRef.current++
					comboRef.current = 0
					livesRef.current = Math.max(0, livesRef.current - 1)
					onLivesChange(livesRef.current)
					hapticManager.miss()
					audioManager.playMiss()
					noteManager.triggerMiss(note.id)

					// Game over check
					if (livesRef.current <= 0) {
						gameOverRef.current = true
						audioManager.stopBackgroundBeat()
						audioManager.releaseAllSustainedNotes()
						onGameOver(pointsRef.current)
					}
				}

				// Remove if way past hit zone (for hold notes, account for beam length)
				const cullDistance = note.isHold
					? HIGHWAY_3D.hitZoneZ + 3 + note.holdDurationZ
					: HIGHWAY_3D.hitZoneZ + 3
				return note.y < cullDistance
			})

			// ── Update effects ──
			hitEffectsRef.current = hitEffectsRef.current.filter(
				effect => now - effect.time < 500
			)

			// ── Update 3D visuals ──
			noteManager.updateAnimations(delta)
			highway.updateBeatMarkers(transportTime, currentBpm)
			highway.updateReceptors(delta)
			bgFX.update(delta, transportTime, currentBpm)
		})

		sceneManager.start()

		return () => {
			clearInterval(uiInterval)
			if (levelUpTimeoutRef.current) {
				clearTimeout(levelUpTimeoutRef.current)
			}
			audioManager.releaseAllSustainedNotes()
			audioManager.stopBackgroundBeat()
			audioManager.dispose()
			bgFX.dispose()
			noteManager.dispose()
			highway.dispose()
			sceneManager.dispose()
			engineRef.current = null
		}
		// eslint-disable-next-line react-hooks/exhaustive-deps
	}, [])

	// ── Touch handler (exposed to parent) ──
	const handleLaneTouch = useCallback(
		(lane: number) => {
			heldLanesRef.current[lane] = true
			hapticManager.buttonTap()
			checkHit(lane)
		},
		[checkHit]
	)

	const handleLaneTouchEnd = useCallback(
		(lane: number) => {
			heldLanesRef.current[lane] = false
			lastKeyReleaseTimeRef.current[lane] = Date.now()
			handleHoldRelease(lane)
		},
		[handleHoldRelease]
	)

	return (
		<div className="game-rhythm-container" style={{ minHeight: 600 }}>
			{/* Three.js canvas container */}
			<div
				ref={containerRef}
				className="game-rhythm-canvas"
				style={{
					touchAction: 'none',
					userSelect: 'none',
					minHeight: 600,
				}}
			/>

			{/* Touch controls — 4 columns with lane-colored highlights */}
			<div className="game-rhythm-touch-controls" style={{ pointerEvents: 'auto' }}>
				{[0, 1, 2, 3].map(lane => (
					<button
						key={lane}
						className="game-rhythm-lane-btn"
						style={{ backgroundColor: LANE_COLOR_ARRAY[lane] }}
						onTouchStart={e => {
							e.preventDefault()
							handleLaneTouch(lane)
						}}
						onTouchEnd={() => {
							handleLaneTouchEnd(lane)
						}}
					/>
				))}
			</div>
		</div>
	)
}

export default RhythmHighway3DCore
