import {
	Scene,
	Mesh,
	PlaneGeometry,
	MeshStandardMaterial,
	MeshBasicMaterial,
	TorusGeometry,
	Color,
} from 'three'
import { HIGHWAY_3D, LANE_COUNT, DEFAULT_LANE_COLORS } from '../constants'

const LANE_COLOR_ARRAY = [
	DEFAULT_LANE_COLORS.lane0,
	DEFAULT_LANE_COLORS.lane1,
	DEFAULT_LANE_COLORS.lane2,
	DEFAULT_LANE_COLORS.lane3,
]

export class HighwayBuilder {
	private meshes: Mesh[] = []
	private beatMarkers: Mesh[] = []
	private receptors: Mesh[] = []
	private hitZoneLine: Mesh | null = null

	/** Total number of scrolling beat markers */
	private static readonly BEAT_MARKER_COUNT = 12

	build(scene: Scene, brandColor: string) {
		this.buildRoad(scene)
		this.buildLaneSeparators(scene)
		this.buildRoadEdges(scene, brandColor)
		this.buildBeatMarkers(scene)
		this.buildHitZone(scene, brandColor)
		this.buildReceptors(scene)
	}

	/** Dark road surface on X-Z plane */
	private buildRoad(scene: Scene) {
		const geo = new PlaneGeometry(HIGHWAY_3D.roadWidth, HIGHWAY_3D.roadLength)
		geo.rotateX(-Math.PI / 2)
		const mat = new MeshStandardMaterial({
			color: 0x0a0a12,
			roughness: 0.7,
			metalness: 0.1,
			transparent: true,
			opacity: 1.0,
		})
		const road = new Mesh(geo, mat)
		road.renderOrder = 1
		// Centre the road so hitZoneZ=0 is at the near end
		road.position.set(0, -0.01, -HIGHWAY_3D.roadLength / 2)
		scene.add(road)
		this.meshes.push(road)
	}

	/** 5 lane separator lines (edges + 3 internal) */
	private buildLaneSeparators(scene: Scene) {
		const halfW = HIGHWAY_3D.roadWidth / 2
		for (let i = 0; i <= LANE_COUNT; i++) {
			const x = -halfW + i * HIGHWAY_3D.laneWidth
			const geo = new PlaneGeometry(0.02, HIGHWAY_3D.roadLength)
			geo.rotateX(-Math.PI / 2)
			const mat = new MeshBasicMaterial({
				color: 0xffffff,
				transparent: true,
				opacity: 0.25,
			})
			const line = new Mesh(geo, mat)
			line.renderOrder = 1
			line.position.set(x, 0.005, -HIGHWAY_3D.roadLength / 2)
			scene.add(line)
			this.meshes.push(line)
		}
	}

	/** Glowing edge strips with brand colour */
	private buildRoadEdges(scene: Scene, brandColor: string) {
		const halfW = HIGHWAY_3D.roadWidth / 2
		const c = new Color(brandColor)
		for (const side of [-1, 1]) {
			const x = side * halfW
			const geo = new PlaneGeometry(0.06, HIGHWAY_3D.roadLength)
			geo.rotateX(-Math.PI / 2)
			const mat = new MeshStandardMaterial({
				color: c,
				emissive: c,
				emissiveIntensity: 0.6,
				transparent: true,
				opacity: 0.8,
			})
			const edge = new Mesh(geo, mat)
			edge.renderOrder = 1
			edge.position.set(x, 0.006, -HIGHWAY_3D.roadLength / 2)
			scene.add(edge)
			this.meshes.push(edge)
		}
	}

	/** Horizontal beat-marker strips that scroll in Z */
	private buildBeatMarkers(scene: Scene) {
		for (let i = 0; i < HighwayBuilder.BEAT_MARKER_COUNT; i++) {
			const geo = new PlaneGeometry(HIGHWAY_3D.roadWidth - 0.2, 0.03)
			geo.rotateX(-Math.PI / 2)
			const mat = new MeshBasicMaterial({
				color: 0xffffff,
				transparent: true,
				opacity: 0.1,
			})
			const marker = new Mesh(geo, mat)
			marker.renderOrder = 1
			// Spread evenly along road length
			const z =
				HIGHWAY_3D.hitZoneZ -
				(i / HighwayBuilder.BEAT_MARKER_COUNT) * HIGHWAY_3D.roadLength
			marker.position.set(0, 0.004, z)
			scene.add(marker)
			this.beatMarkers.push(marker)
			this.meshes.push(marker)
		}
	}

	/** Thin glowing strip across the road at the hit zone */
	private buildHitZone(scene: Scene, brandColor: string) {
		const geo = new PlaneGeometry(HIGHWAY_3D.roadWidth, 0.06)
		geo.rotateX(-Math.PI / 2)
		const c = new Color(brandColor)
		const mat = new MeshStandardMaterial({
			color: c,
			emissive: c,
			emissiveIntensity: 1.0,
			transparent: true,
			opacity: 0.9,
		})
		const line = new Mesh(geo, mat)
		line.renderOrder = 1
		line.position.set(0, 0.008, HIGHWAY_3D.hitZoneZ)
		scene.add(line)
		this.hitZoneLine = line
		this.meshes.push(line)
	}

	/** Four torus receptors at the hit zone, one per lane */
	private buildReceptors(scene: Scene) {
		const halfW = HIGHWAY_3D.roadWidth / 2
		for (let i = 0; i < LANE_COUNT; i++) {
			const x = -halfW + HIGHWAY_3D.laneWidth * (i + 0.5)
			const c = new Color(LANE_COLOR_ARRAY[i])
			const geo = new TorusGeometry(HIGHWAY_3D.receptorRadius, 0.06, 8, 24)
			const mat = new MeshStandardMaterial({
				color: c,
				emissive: c,
				emissiveIntensity: 0.5,
				transparent: true,
				opacity: 0.7,
			})
			const torus = new Mesh(geo, mat)
			torus.renderOrder = 2
			torus.rotation.x = -Math.PI / 2
			torus.position.set(x, HIGHWAY_3D.noteY, HIGHWAY_3D.hitZoneZ)
			scene.add(torus)
			this.receptors.push(torus)
			this.meshes.push(torus)
		}
	}

	/**
	 * Scroll beat markers to keep them synced with BPM.
	 * @param elapsedTime  Transport time in ms
	 * @param bpm          Current beats per minute
	 */
	updateBeatMarkers(elapsedTime: number, bpm: number) {
		const beatInterval = 60000 / bpm
		// World-Z distance between beats (same ratio as road)
		const zPerBeat = HIGHWAY_3D.roadLength / HighwayBuilder.BEAT_MARKER_COUNT
		// Current phase within a beat cycle (0–1)
		const phase = ((elapsedTime % beatInterval) / beatInterval) % 1

		for (let i = 0; i < this.beatMarkers.length; i++) {
			const baseZ = HIGHWAY_3D.hitZoneZ - i * zPerBeat
			const z = baseZ + phase * zPerBeat
			// Wrap when past hit zone
			this.beatMarkers[i].position.z =
				z > HIGHWAY_3D.hitZoneZ + zPerBeat ? z - HIGHWAY_3D.roadLength : z
		}
	}

	/** Flash a receptor when its lane is hit */
	flashReceptor(lane: number) {
		const r = this.receptors[lane]
		if (!r) return
		const mat = r.material as MeshStandardMaterial
		mat.emissiveIntensity = 1.2
		mat.opacity = 1
		// Fade back over ~200 ms handled in update
	}

	/** Gradually restore receptor glow after flash */
	updateReceptors(delta: number) {
		for (const r of this.receptors) {
			const mat = r.material as MeshStandardMaterial
			if (mat.emissiveIntensity > 0.5) {
				mat.emissiveIntensity = Math.max(0.5, mat.emissiveIntensity - delta * 4)
			}
			if (mat.opacity > 0.7) {
				mat.opacity = Math.max(0.7, mat.opacity - delta * 4)
			}
		}
	}

	/** Get the world X position for the centre of a lane. */
	getLaneX(lane: number): number {
		const halfW = HIGHWAY_3D.roadWidth / 2
		return -halfW + HIGHWAY_3D.laneWidth * (lane + 0.5)
	}

	dispose() {
		for (const mesh of this.meshes) {
			mesh.geometry.dispose()
			if (Array.isArray(mesh.material)) {
				mesh.material.forEach(m => m.dispose())
			} else {
				mesh.material.dispose()
			}
		}
		this.meshes = []
		this.beatMarkers = []
		this.receptors = []
		this.hitZoneLine = null
	}
}
