import {
	Scene,
	Mesh,
	SphereGeometry,
	BoxGeometry,
	MeshStandardMaterial,
	Color,
} from 'three'
import { HIGHWAY_3D, DEFAULT_LANE_COLORS, HOLD_BEAM_WIDTH } from '../constants'

const LANE_COLOR_ARRAY = [
	DEFAULT_LANE_COLORS.lane0,
	DEFAULT_LANE_COLORS.lane1,
	DEFAULT_LANE_COLORS.lane2,
	DEFAULT_LANE_COLORS.lane3,
]

const POOL_SIZE = 40

/** Internal state for a single note sphere */
interface NoteState {
	mesh: Mesh
	/** Original lane colour (for restoring after hit animation) */
	baseColor: Color
	active: boolean
	/** Unique id matching the game-logic Note.id */
	noteId: number
	lane: number
	/** true once hit animation started */
	animating: boolean
	animElapsed: number
	// Hold note beam
	beam: Mesh
	isHold: boolean
	holdDurationZ: number
	beamActive: boolean
}

export class NoteManager {
	private pool: NoteState[] = []
	private sharedGeometry: SphereGeometry
	private sharedGlowGeometry: SphereGeometry
	private sharedBeamGeometry: BoxGeometry

	constructor(private scene: Scene) {
		this.sharedGeometry = new SphereGeometry(HIGHWAY_3D.noteRadius, 16, 12)
		this.sharedGlowGeometry = new SphereGeometry(
			HIGHWAY_3D.noteRadius * 2.5,
			12,
			8
		)
		// Beam geometry: 1x1x1 box, scaled per-note
		this.sharedBeamGeometry = new BoxGeometry(1, 1, 1)

		for (let i = 0; i < POOL_SIZE; i++) {
			const mat = new MeshStandardMaterial({
				color: 0xffffff,
				emissive: 0xffffff,
				emissiveIntensity: 0.8,
				metalness: 0.6,
				roughness: 0.2,
				transparent: true,
				opacity: 1,
			})
			const mesh = new Mesh(this.sharedGeometry, mat)
			mesh.renderOrder = 2
			mesh.visible = false
			scene.add(mesh)

			// Create beam mesh for hold notes
			const beamMat = new MeshStandardMaterial({
				color: 0xffffff,
				emissive: 0xffffff,
				emissiveIntensity: 0.4,
				metalness: 0.3,
				roughness: 0.4,
				transparent: true,
				opacity: 0.7,
			})
			const beam = new Mesh(this.sharedBeamGeometry, beamMat)
			beam.renderOrder = 1
			beam.visible = false
			scene.add(beam)

			this.pool.push({
				mesh,
				baseColor: new Color(0xffffff),
				active: false,
				noteId: -1,
				lane: 0,
				animating: false,
				animElapsed: 0,
				beam,
				isHold: false,
				holdDurationZ: 0,
				beamActive: false,
			})
		}
	}

	/** Get the lane centre X from a lane index */
	private laneX(lane: number): number {
		const halfW = HIGHWAY_3D.roadWidth / 2
		return -halfW + HIGHWAY_3D.laneWidth * (lane + 0.5)
	}

	/** Activate a pooled sphere for a new note */
	spawn(
		noteId: number,
		lane: number,
		isHold: boolean = false,
		holdDurationZ: number = 0
	): void {
		const slot = this.pool.find(s => !s.active)
		if (!slot) return // pool exhausted – rare

		const c = new Color(LANE_COLOR_ARRAY[lane])
		const mat = slot.mesh.material as MeshStandardMaterial
		mat.color.copy(c)
		mat.emissive.copy(c)
		mat.emissiveIntensity = 0.7
		mat.opacity = 1
		slot.baseColor.copy(c)

		const x = this.laneX(lane)
		slot.mesh.position.set(x, HIGHWAY_3D.noteY, HIGHWAY_3D.spawnZ)
		slot.mesh.scale.set(1, 1, 1)
		slot.mesh.visible = true

		slot.active = true
		slot.noteId = noteId
		slot.lane = lane
		slot.animating = false
		slot.animElapsed = 0
		slot.isHold = isHold
		slot.holdDurationZ = holdDurationZ
		slot.beamActive = false

		// If hold note, set up the beam behind the sphere
		if (isHold && holdDurationZ > 0) {
			const beamMat = slot.beam.material as MeshStandardMaterial
			beamMat.color.copy(c)
			beamMat.emissive.copy(c)
			beamMat.emissiveIntensity = 0.4
			beamMat.opacity = 0.7

			// Beam stretches behind the sphere (negative Z direction from sphere)
			const beamWidth = HOLD_BEAM_WIDTH * 2
			const beamHeight = HIGHWAY_3D.noteRadius * 0.8
			slot.beam.scale.set(beamWidth, beamHeight, holdDurationZ)
			slot.beam.position.set(
				x,
				HIGHWAY_3D.noteY,
				HIGHWAY_3D.spawnZ - holdDurationZ / 2
			)
			slot.beam.visible = true
			slot.beamActive = true
		}
	}

	/** Move a note toward the hit zone (increment Z). Returns new Z. */
	moveNote(noteId: number, dz: number): number {
		const slot = this.pool.find(
			s => s.active && s.noteId === noteId && !s.animating
		)
		if (!slot) return HIGHWAY_3D.hitZoneZ
		slot.mesh.position.z += dz

		// Move beam along with sphere
		if (slot.beamActive) {
			slot.beam.position.z += dz
		}

		return slot.mesh.position.z
	}

	/**
	 * Update hold beam visual as the note passes through the hit zone.
	 * Consumed portion shrinks from the front as the head moves past hitZoneZ.
	 * Glows brighter when being held.
	 */
	updateHoldBeam(noteId: number, headZ: number, isBeingHeld: boolean): void {
		const slot = this.pool.find(
			s => s.active && s.noteId === noteId && s.beamActive
		)
		if (!slot) return

		const beamMat = slot.beam.material as MeshStandardMaterial

		// The head has passed the hit zone - shrink beam from front
		if (headZ > HIGHWAY_3D.hitZoneZ) {
			const consumed = headZ - HIGHWAY_3D.hitZoneZ
			const remaining = Math.max(0, slot.holdDurationZ - consumed)

			if (remaining <= 0.01) {
				// Beam fully consumed
				slot.beam.visible = false
				slot.beamActive = false
				return
			}

			// Reposition and rescale: beam tail stays where it was
			const tailZ = headZ - slot.holdDurationZ
			const beamWidth = HOLD_BEAM_WIDTH * 2
			const beamHeight = HIGHWAY_3D.noteRadius * 0.8
			slot.beam.scale.set(beamWidth, beamHeight, remaining)
			slot.beam.position.z = tailZ + remaining / 2
		}

		// Glow effect based on hold state
		if (isBeingHeld) {
			beamMat.emissiveIntensity = 0.8
			beamMat.opacity = 0.9
		} else {
			beamMat.emissiveIntensity = 0.2
			beamMat.opacity = 0.4
		}
	}

	/** Gold flash on beam + sphere for successful hold completion */
	triggerHoldComplete(noteId: number): void {
		const slot = this.pool.find(s => s.active && s.noteId === noteId)
		if (!slot) return

		const gold = new Color('#ffd700')
		const mat = slot.mesh.material as MeshStandardMaterial
		mat.color.copy(gold)
		mat.emissive.copy(gold)
		mat.emissiveIntensity = 1.2

		if (slot.beamActive) {
			const beamMat = slot.beam.material as MeshStandardMaterial
			beamMat.color.copy(gold)
			beamMat.emissive.copy(gold)
			beamMat.emissiveIntensity = 1.0
			beamMat.opacity = 1.0
		}

		// Start hit animation
		slot.animating = true
		slot.animElapsed = 0
	}

	/** Dim/red fade for early release */
	triggerHoldDrop(noteId: number): void {
		const slot = this.pool.find(s => s.active && s.noteId === noteId)
		if (!slot) return

		const dim = new Color('#ff6666')
		if (slot.beamActive) {
			const beamMat = slot.beam.material as MeshStandardMaterial
			beamMat.color.copy(dim)
			beamMat.emissive.copy(dim)
			beamMat.emissiveIntensity = 0.3
			beamMat.opacity = 0.3
		}

		// Start hit animation on sphere
		slot.animating = true
		slot.animElapsed = 0
		const mat = slot.mesh.material as MeshStandardMaterial
		mat.color.copy(dim)
		mat.emissive.copy(dim)
	}

	/** Start hit animation (scale up, change colour) */
	triggerHit(noteId: number, hitType: 'perfect' | 'good' | 'bad'): void {
		const slot = this.pool.find(s => s.active && s.noteId === noteId)
		if (!slot) return

		slot.animating = true
		slot.animElapsed = 0

		const mat = slot.mesh.material as MeshStandardMaterial
		const hitColor =
			hitType === 'perfect'
				? new Color('#ffd700')
				: hitType === 'good'
					? new Color('#c0c0c0')
					: new Color('#ff8c00')
		mat.color.copy(hitColor)
		mat.emissive.copy(hitColor)
		mat.emissiveIntensity = 1.0
	}

	/** Start miss animation (turn red, fade) */
	triggerMiss(noteId: number): void {
		const slot = this.pool.find(s => s.active && s.noteId === noteId)
		if (!slot) return

		slot.animating = true
		slot.animElapsed = 0

		const mat = slot.mesh.material as MeshStandardMaterial
		const red = new Color('#ff4444')
		mat.color.copy(red)
		mat.emissive.copy(red)
		mat.emissiveIntensity = 0.8

		// Also dim beam on miss
		if (slot.beamActive) {
			const beamMat = slot.beam.material as MeshStandardMaterial
			beamMat.color.copy(red)
			beamMat.emissive.copy(red)
			beamMat.emissiveIntensity = 0.3
			beamMat.opacity = 0.3
		}
	}

	/** Remove (recycle) a note immediately */
	remove(noteId: number): void {
		const slot = this.pool.find(s => s.active && s.noteId === noteId)
		if (!slot) return
		slot.active = false
		slot.mesh.visible = false
		slot.beam.visible = false
		slot.beamActive = false
	}

	/** Tick all active hit/miss animations. Call once per frame. */
	updateAnimations(delta: number): void {
		for (const slot of this.pool) {
			if (!slot.active || !slot.animating) continue

			slot.animElapsed += delta * 1000 // convert to ms
			const progress = Math.min(slot.animElapsed / 200, 1)

			const mat = slot.mesh.material as MeshStandardMaterial
			const scale = 1 + progress * 0.5
			slot.mesh.scale.set(scale, scale, scale)
			mat.opacity = Math.max(0, 1 - progress)

			// Fade beam as well
			if (slot.beamActive) {
				const beamMat = slot.beam.material as MeshStandardMaterial
				beamMat.opacity = Math.max(0, beamMat.opacity * (1 - progress * 0.5))
			}

			if (progress >= 1) {
				slot.active = false
				slot.mesh.visible = false
				slot.beam.visible = false
				slot.beamActive = false
			}
		}
	}

	/** Hide all active notes (e.g., on level transition) */
	clearAll(): void {
		for (const slot of this.pool) {
			slot.active = false
			slot.mesh.visible = false
			slot.animating = false
			slot.beam.visible = false
			slot.beamActive = false
		}
	}

	/** Check if a note id is currently visible */
	isActive(noteId: number): boolean {
		return this.pool.some(s => s.active && s.noteId === noteId)
	}

	dispose(): void {
		this.sharedGeometry.dispose()
		this.sharedGlowGeometry.dispose()
		this.sharedBeamGeometry.dispose()
		for (const slot of this.pool) {
			;(slot.mesh.material as MeshStandardMaterial).dispose()
			;(slot.beam.material as MeshStandardMaterial).dispose()
		}
		this.pool = []
	}
}
