export type InstrumentName =
	| 'piano'
	| 'music-box'
	| 'guitar'
	| 'synth-lead'
	| 'chiptune'
	| 'strings'
	| 'flute'
	| 'organ'

export interface InstrumentPreset {
	oscillatorType: 'sine' | 'triangle' | 'sawtooth' | 'square'
	envelope: {
		attack: number
		decay: number
		sustain: number
		release: number
	}
	volume: number
	sparkleOctaveOffset: number
}

export const INSTRUMENT_PRESETS: Record<InstrumentName, InstrumentPreset> = {
	piano: {
		oscillatorType: 'sine',
		envelope: { attack: 0.01, decay: 0.2, sustain: 0.3, release: 0.5 },
		volume: -10,
		sparkleOctaveOffset: 2,
	},
	'music-box': {
		oscillatorType: 'sine',
		envelope: { attack: 0.001, decay: 0.4, sustain: 0.1, release: 0.8 },
		volume: -8,
		sparkleOctaveOffset: 3,
	},
	guitar: {
		oscillatorType: 'triangle',
		envelope: { attack: 0.005, decay: 0.3, sustain: 0.2, release: 0.4 },
		volume: -10,
		sparkleOctaveOffset: 1,
	},
	'synth-lead': {
		oscillatorType: 'sawtooth',
		envelope: { attack: 0.01, decay: 0.15, sustain: 0.5, release: 0.3 },
		volume: -12,
		sparkleOctaveOffset: 2,
	},
	chiptune: {
		oscillatorType: 'square',
		envelope: { attack: 0.001, decay: 0.1, sustain: 0.4, release: 0.1 },
		volume: -14,
		sparkleOctaveOffset: 2,
	},
	strings: {
		oscillatorType: 'sawtooth',
		envelope: { attack: 0.15, decay: 0.3, sustain: 0.7, release: 0.8 },
		volume: -12,
		sparkleOctaveOffset: 1,
	},
	flute: {
		oscillatorType: 'sine',
		envelope: { attack: 0.05, decay: 0.1, sustain: 0.6, release: 0.4 },
		volume: -8,
		sparkleOctaveOffset: 2,
	},
	organ: {
		oscillatorType: 'square',
		envelope: { attack: 0.005, decay: 0.01, sustain: 0.9, release: 0.1 },
		volume: -14,
		sparkleOctaveOffset: 2,
	},
}

export function getInstrumentPreset(name?: InstrumentName): InstrumentPreset {
	return INSTRUMENT_PRESETS[name || 'piano']
}
