// Shuffle bag system - ensures all songs in a tier play before any repeats
const shuffleBags: Partial<Record<Difficulty, Song[]>> = {}
const shuffleIndices: Partial<Record<Difficulty, number>> = {}

function shuffleArray<T>(arr: T[]): T[] {
	const shuffled = [...arr]
	for (let i = shuffled.length - 1; i > 0; i--) {
		const j = Math.floor(Math.random() * (i + 1))
		;[shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]]
	}
	return shuffled
}

function getNextSongFromBag(difficulty: Difficulty): Song {
	// Initialize bag if needed or if exhausted
	if (
		!shuffleBags[difficulty] ||
		shuffleIndices[difficulty] === undefined ||
		shuffleIndices[difficulty]! >= shuffleBags[difficulty]!.length
	) {
		shuffleBags[difficulty] = shuffleArray(songsByDifficulty[difficulty])
		shuffleIndices[difficulty] = 0
	}

	const song = shuffleBags[difficulty]![shuffleIndices[difficulty]!]
	shuffleIndices[difficulty] = shuffleIndices[difficulty]! + 1
	return song
}

// Reset shuffle bags (call on game restart for fresh shuffle)
export function resetSongShuffle(): void {
	for (const key of Object.keys(shuffleBags)) {
		delete shuffleBags[key as Difficulty]
		delete shuffleIndices[key as Difficulty]
	}
}

// Get song for a specific level (fixed 8-level progression)
// Level 1 = very-easy, Levels 2-3 = easy, Levels 4-5 = medium, Levels 6-7 = hard, Level 8 = very-hard
export function getSongForLevel(level: number): {
	song: Song
	cycle: number
	speedMultiplier: number
	difficulty: Difficulty
} {
	// Clamp level to valid range
	const clampedLevel = Math.min(Math.max(level, 1), TOTAL_LEVELS)

	// Map level to difficulty from the fixed array (level 1 = index 0)
	const difficulty = LEVEL_DIFFICULTIES[clampedLevel - 1]

	// Get next song from shuffle bag (no repeats until all songs played)
	const song = getNextSongFromBag(difficulty)

	return {
		song,
		cycle: 0,
		speedMultiplier: 1.0,
		difficulty,
	}
}

// Get song by ID
export function getSongById(id: string): Song | undefined {
	return songLibrary.find(s => s.metadata.id === id)
}

// Get all songs
export function getAllSongs(): Song[] {
	return songLibrary
}

// Get song metadata list (for UI display)
export function getSongList(): Array<{
	id: string
	title: string
	artist: string
	difficulty: Difficulty
}> {
	return songLibrary.map(s => ({
		id: s.metadata.id,
		title: s.metadata.title,
		artist: s.metadata.artist,
		difficulty: s.metadata.difficulty,
	}))
}

